app waspProject {
  wasp: {
    version: "^0.15.0"
  },
  title: "Wasp Role Auth",
  auth: {
    userEntity: User,
    methods: {
      usernameAndPassword: {}
    },
    onAuthFailedRedirectTo: "/login"
  }
}

route RootRoute { path: "/", to: MainPage }
page MainPage {
  component: import { MainPage } from "@src/MainPage"
}

route LoginRoute { path: "/login", to: LoginPage }
page LoginPage {
  component: import { LoginPage } from "@src/LoginPage"
}

route SignupRoute { path: "/signup", to: SignupPage }
page SignupPage {
  component: import { SignupPage } from "@src/SignupPage"
}

entity User {
  id Int @id @default(autoincrement())
}

datasource db {
  provider = "sqlite"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

// Use Prisma Schema file to define your entities: https://www.prisma.io/docs/concepts/components/prisma-schema.
// Run `wasp db migrate-dev` in the CLI to create the database tables,
// then run `wasp db studio` to open Prisma Studio and view your db models.
model User {
  id       String @id @default(uuid())
  username String

  tasks Task[]
  tags  Tag[]
}

model Task {
  id          String   @id @default(uuid())
  description String
  isDone      Boolean  @default(false)
  createdAt   DateTime @default(now())

  user   User   @relation(fields: [userId], references: [id])
  userId String

  tags Tag[]
}

model Tag {
  id    String @id @default(uuid())
  name  String @unique
  color String

  user   User   @relation(fields: [userId], references: [id])
  userId String

  tasks Task[]
}

import React from 'react'
import { Link } from 'react-router-dom'
import { useAuth, logout } from 'wasp/client/auth'

export const MainPage = () => {
  const { data: user } = useAuth()
  return (
    <div>
      <h1>Home</h1>
      {user ? (
        <div>
          <p>Welcome, {user.username}!</p>
          <button onClick={logout}>Logout</button>
        </div>
      ) : (
        <p>Please <Link to="/login">login</Link> or <Link to="/signup">signup</Link></p>
      )}
    </div>
  )
}

