import React, { useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { AuthUser } from 'wasp/auth'

type AdminPageProps = {
  user: AuthUser
}

export const AdminPage = ({ user }: AdminPageProps) => {
  const navigate = useNavigate()

  useEffect(() => {
    if (user.role !== 'ADMIN') {
      navigate('/')
    }
  }, [user, navigate])

  if (user.role !== 'ADMIN') {
    return null
  }

  return (
    <div>
      <h1>Admin Dashboard</h1>
    </div>
  )
}

